INSERT INTO public.nodes VALUES (1570, '6000 req/s real', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-02 20:44:54.974892+00');
INSERT INTO public.nodes VALUES (1600, '50000 transactions/day', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-02 20:44:55.213405+00');
INSERT INTO public.nodes VALUES (1602, '2 hours verbal', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-02 20:44:55.231513+00');
INSERT INTO public.nodes VALUES (1604, '4 hours', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-02 20:44:55.249238+00');
INSERT INTO public.nodes VALUES (1612, '100000 transactions/day', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-02 20:44:55.311866+00');
INSERT INTO public.nodes VALUES (1634, 'If uncertain, ask', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:16.334526+00');
INSERT INTO public.nodes VALUES (1636, 'If multiple interpretations exist, present them - don''t pick silently', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:16.34089+00');
INSERT INTO public.nodes VALUES (1638, 'If a simpler approach exists, say so. Push back when warranted.', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:16.347651+00');
INSERT INTO public.nodes VALUES (1640, 'If something is unclear, stop. Name what''s confusing. Ask.', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:16.35524+00');
INSERT INTO public.nodes VALUES (1642, 'Don''t assume, don''t hide confusion, surface tradeoffs', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:16.363211+00');
INSERT INTO public.nodes VALUES (1643, 'coding approach', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:29.227629+00');
INSERT INTO public.nodes VALUES (1644, 'true', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:29.229447+00');
INSERT INTO public.nodes VALUES (1646, 'unrequested features', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:29.236555+00');
INSERT INTO public.nodes VALUES (1648, 'abstractions for single-use code', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:29.243232+00');
INSERT INTO public.nodes VALUES (1650, 'unrequested flexibility or configurability', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:29.24985+00');
INSERT INTO public.nodes VALUES (1652, 'error handling for impossible scenarios', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:29.256197+00');
INSERT INTO public.nodes VALUES (1654, 'when code can be shorter', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:29.263945+00');
INSERT INTO public.nodes VALUES (1656, 'on complexity', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:29.2706+00');
INSERT INTO public.nodes VALUES (1658, 'touch only what you must and clean up only your own mess', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:44.170017+00');
INSERT INTO public.nodes VALUES (1660, '''improve'' adjacent code, comments, or formatting', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:44.177593+00');
INSERT INTO public.nodes VALUES (1662, 'refactor things that aren''t broken', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:44.185068+00');
INSERT INTO public.nodes VALUES (1664, 'match existing style, even if you''d do it differently', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:44.191828+00');
INSERT INTO public.nodes VALUES (1666, 'mention unrelated dead code but not delete it', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:44.198823+00');
INSERT INTO public.nodes VALUES (1668, 'remove imports/variables/functions that your changes made unused', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:44.205583+00');
INSERT INTO public.nodes VALUES (1670, 'remove pre-existing dead code unless asked', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:44.212313+00');
INSERT INTO public.nodes VALUES (1672, 'ensure every changed line traces directly to the user''s request', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:44.218343+00');
INSERT INTO public.nodes VALUES (1673, 'Tasks', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:53.883992+00');
INSERT INTO public.nodes VALUES (1674, 'verifiable goals', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:53.885441+00');
INSERT INTO public.nodes VALUES (1675, 'Multi-step tasks', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:53.891938+00');
INSERT INTO public.nodes VALUES (1676, 'a brief plan with steps and verifications', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:53.893749+00');
INSERT INTO public.nodes VALUES (1677, 'Strong success criteria', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:53.899426+00');
INSERT INTO public.nodes VALUES (1678, 'independent looping', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:53.901082+00');
INSERT INTO public.nodes VALUES (1679, 'Weak criteria', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:53.906486+00');
INSERT INTO public.nodes VALUES (1680, 'constant clarification', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:53.90841+00');
INSERT INTO public.nodes VALUES (1681, 'These guidelines', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:53.91402+00');
INSERT INTO public.nodes VALUES (1682, 'fewer unnecessary changes in diffs, fewer rewrites due to overcomplication, and clarifying questions come before implementation rather than after mistakes', NULL, NULL, NULL, DEFAULT, 'active', NULL, '2026-07-03 08:58:53.91542+00');
